import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;
import java.util.HashMap;
import java.util.Map;

public class XMLParser {
    public static Map<String, Object> parseConfig(String xml) throws Exception {
        Map<String, Object> config = new HashMap<>();
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(new org.jdom2.input.StringReader(xml));

        Element root = document.getDocumentElement();
        NodeList configNodes = root.getElementsByTagName("config");
        if (configNodes.getLength() > 0) {
            Element configElement = (Element) configNodes.item(0);
            for (NodeList nodeList : configElement.getChildNodes()) {
                if (nodeList.getItem(0).getNodeType() == Node.ELEMENT_NODE) {
                    Element element = (Element) nodeList.getItem(0);
                    String key = element.getAttribute("key");
                    Object value;
                    if ("string".equals(element.getAttribute("type"))) {
                        value = element.getTextContent();
                    } else if ("integer".equals(element.getAttribute("type"))) {
                        value = Integer.parseInt(element.getTextContent());
                    } else {
                        throw new RuntimeException("Unsupported type: " + element.getAttribute("type"));
                    }
                    config.put(key, value);
                }
            }
        }
        return config;
    }
}